function renderNotes() {
  detailNodes.notesList.innerHTML = '';
  if (!selectedContact) return;
  detailNodes.notesHeader.textContent = 'Notes for ' + (contacts.get(selectedContact)?.name || '');
  const items = notes.byContact(selectedContact)
    .sort((a, b) => (b['created-at'] || '').localeCompare(a['created-at'] || ''));
  if (items.length === 0) {
    const empty = document.createElement('div');
    empty.className = 'text-sm text-muted-foreground';
    empty.textContent = 'No notes yet';
    detailNodes.notesList.appendChild(empty);
    return;
  }
  for (const item of items) {
    const el = document.createElement('div');
    el.className = 'p-2 border border-border rounded-md flex justify-between items-start gap-2';
    const elBody = document.createElement('div');
    elBody.className = 'flex-1 min-w-0';
    const contentEl = document.createElement('p');
    contentEl.className = 'text-sm';
    contentEl.textContent = item['content'] || '';
    elBody.appendChild(contentEl);
    const created_atEl = document.createElement('span');
    created_atEl.className = 'text-xs text-muted-foreground mt-1 block';
    created_atEl.textContent = item['created-at'] || '';
    elBody.appendChild(created_atEl);
    el.appendChild(elBody);
    const delBtn = document.createElement('button');
    delBtn.className = 'text-muted-foreground hover:text-red-600 text-sm px-1 flex-shrink-0';
    delBtn.textContent = '\u00d7';
    delBtn.addEventListener('click', () => notes.remove(item.eid));
    el.appendChild(delBtn);
    detailNodes.notesList.appendChild(el);
  }
}

function renderDetail() {
  if (!selectedContact) {
    detailNodes.emptyState.style.display = '';
    detailNodes.wrapper.style.display = 'none';
    detailNodes.title.textContent = '';
    detailNodes.subtitle.textContent = '';
    detailNodes.field_name.textContent = '';
    detailNodes.field_email.textContent = '';
    detailNodes.field_company.textContent = '';
    detailNodes.field_status.textContent = '';
    detailNodes.field_display_name.textContent = '';
    return;
  }
  const entity = contacts.get(selectedContact);
  if (!entity) {
    detailNodes.emptyState.style.display = '';
    detailNodes.wrapper.style.display = 'none';
    return;
  }
  detailNodes.emptyState.style.display = 'none';
  detailNodes.wrapper.style.display = '';

  detailNodes.title.textContent = entity.name || '';
  detailNodes.subtitle.textContent = entity.email || '';

  detailNodes.field_name.textContent = entity.name || '';
  detailNodes.field_email.textContent = entity.email || '';
  detailNodes.field_company.textContent = entity.company || '';
  detailNodes.field_status.textContent = entity.status || '';
  detailNodes.field_display_name.textContent = (entity.name || '') + " @ " + (entity.company || '');

  detailNodes.tabOverview.className = activeTab === 'overview'
    ? 'px-4 py-2 text-sm font-medium border-b-2 border-primary text-foreground'
    : 'px-4 py-2 text-sm font-medium text-muted-foreground';
  detailNodes.tab_notes.className = activeTab === "notes"
    ? 'px-4 py-2 text-sm font-medium border-b-2 border-primary text-foreground'
    : 'px-4 py-2 text-sm font-medium text-muted-foreground';

  detailNodes.overviewContent.style.display = activeTab !== 'overview' ? 'none' : '';
  detailNodes.notesContent.style.display = activeTab !== "notes" ? 'none' : '';
  if (activeTab === "notes") renderNotes();
}


