const rowEls = new Map();

function addRow(entity) {
  const row = document.createElement('div');
  row.className = 'ld-row flex items-center px-4 py-2.5 border-b border-border cursor-pointer transition-colors hover:bg-muted/50';
  const inner = document.createElement('div');
  inner.className = 'flex-1 flex gap-4';
  const nameCell = document.createElement('span');
  nameCell.className = 'text-sm truncate flex-1';
  nameCell.textContent = entity.name || '';
  inner.appendChild(nameCell);
  const emailCell = document.createElement('span');
  emailCell.className = 'text-sm truncate flex-1';
  emailCell.textContent = entity.email || '';
  inner.appendChild(emailCell);
  const companyCell = document.createElement('span');
  companyCell.className = 'text-sm truncate flex-1';
  companyCell.textContent = entity.company || '';
  inner.appendChild(companyCell);
  const statusCell = document.createElement('span');
  statusCell.className = 'text-sm truncate flex-1';
  statusCell.textContent = entity.status || '';
  inner.appendChild(statusCell);
  const display_nameCell = document.createElement('span');
  display_nameCell.className = 'text-sm truncate flex-1 text-muted-foreground italic';
  display_nameCell.textContent = (entity.name || '') + " @ " + (entity.company || '');
  inner.appendChild(display_nameCell);
  row.appendChild(inner);
  row.addEventListener('click', () => selectContact(entity.eid));
  ld_contact_list.appendChild(row);
  rowEls.set(entity.eid, {
    el: row,
    searchText: [entity.name || '', entity.email || '', entity.company || ''].join(' ').toLowerCase(),
    cells: { name: nameCell, email: emailCell, company: companyCell, status: statusCell, display_name: display_nameCell }
  });
}

function removeRow(eid) {
  const entry = rowEls.get(eid);
  if (entry) { entry.el.remove(); rowEls.delete(eid); }
}

function rebuildList() {
  ld_contact_list.innerHTML = '';
  rowEls.clear();
  const sorted = contacts.all().slice().sort((a, b) => (a.name || '').localeCompare(b.name || ''));
  for (const entity of sorted) addRow(entity);
  filterRows();
}

function filterRows() {
  const term = ld_contact_search.value.toLowerCase();
  for (const [, entry] of rowEls) {
    entry.el.hidden = (term !== '' && !entry.searchText.includes(term));
  }
}


// ── Stats ────────────────────────────────────────────
let contactCount = 0;
function updateStats() {
  contactCount = contacts.all().length;
  ld_contact_stats.textContent = 'Total: ' + contactCount;
}


// ── Form ─────────────────────────────────────────────
function handleSubmit(e) {
  e.preventDefault();
  const form_add_contact_name_val = form_add_contact_name.value.trim();
  const form_add_contact_email_val = form_add_contact_email.value.trim();
  const form_add_contact_company_val = form_add_contact_company.value.trim();
  const form_add_contact_status_val = form_add_contact_status.value.trim();
  if (!form_add_contact_name_val) return;
  contacts.add({ name: form_add_contact_name_val, email: form_add_contact_email_val, company: form_add_contact_company_val, status: form_add_contact_status_val || "active" });
  form_add_contact_name.value = '';
  form_add_contact_email.value = '';
  form_add_contact_company.value = '';
  form_add_contact_status.selectedIndex = 0;
}


// ── Persistence ──────────────────────────────────────
function saveDb() {
  try {
    localStorage.setItem("wake-crm-v2", JSON.stringify({
      contacts: contacts.snapshot(),
      notes: notes.snapshot()
    }));
  } catch(_) {}
}
function restoreDb() {
  try {
    const raw = localStorage.getItem("wake-crm-v2");
    if (!raw) return;
    const data = JSON.parse(raw);
    if (Array.isArray(data)) {
      contacts.load(data);
    } else {
      if (data.contacts) contacts.load(data.contacts);
      if (data.notes) notes.load(data.notes);
    }
  } catch(_) {}
}


// ── Compiled update paths ────────────────────────────
const updateAttr = {
  name(eid, value) {
    const rowEntry = rowEls.get(eid);
    const entity = contacts.get(eid);
    if (rowEntry) {
      rowEntry.cells.name.textContent = value;
      rowEntry.searchText = [entity.name || '', entity.email || '', entity.company || ''].join(' ').toLowerCase();
      rowEntry.cells.display_name.textContent = value + " @ " + (entity.company || '');
    }
    if (selectedContact === eid) {
      detailNodes.field_name.textContent = value;
      detailNodes.title.textContent = value;
      detailNodes.notesHeader.textContent = 'Notes for ' + value;
      if (detailNodes.field_display_name) detailNodes.field_display_name.textContent = value + " @ " + (entity.company || '');
    }
    filterRows();
    saveDb();
  },
  email(eid, value) {
    const rowEntry = rowEls.get(eid);
    const entity = contacts.get(eid);
    if (rowEntry) {
      rowEntry.cells.email.textContent = value;
      rowEntry.searchText = [entity.name || '', entity.email || '', entity.company || ''].join(' ').toLowerCase();
    }
    if (selectedContact === eid) {
      detailNodes.field_email.textContent = value;
      detailNodes.subtitle.textContent = value;
    }
    filterRows();
    saveDb();
  },
  company(eid, value) {
    const rowEntry = rowEls.get(eid);
    const entity = contacts.get(eid);
    if (rowEntry) {
      rowEntry.cells.company.textContent = value;
      rowEntry.searchText = [entity.name || '', entity.email || '', entity.company || ''].join(' ').toLowerCase();
      rowEntry.cells.display_name.textContent = (entity.name || '') + " @ " + value;
    }
    if (selectedContact === eid) {
      detailNodes.field_company.textContent = value;

      if (detailNodes.field_display_name) detailNodes.field_display_name.textContent = (entity.name || '') + " @ " + value;
    }
    filterRows();
    saveDb();
  },
  status(eid, value) {
    const rowEntry = rowEls.get(eid);
    if (rowEntry) {
      rowEntry.cells.status.textContent = value;
    }
    if (selectedContact === eid) {
      detailNodes.field_status.textContent = value;
    }
    saveDb();
  }
};


// ── Undo / Redo ─────────────────────────────────────
const undoStack = [];
const redoStack = [];
let undoing = false;
let txBuffer = null;

function recordUndo(entry) {
  if (undoing) return;
  if (txBuffer) { txBuffer.push(entry); return; }
  undoStack.push(entry);
  redoStack.length = 0;
}

function beginTransaction() { txBuffer = []; }
function commitTransaction() {
  if (txBuffer && txBuffer.length > 0) {
    undoStack.push({ type: 'batch', ops: txBuffer });
    redoStack.length = 0;
  }
  txBuffer = null;
}

function applyUndo(op) {
  if (op.type === 'update') op.store.update(op.eid, op.attr, op.old);
  if (op.type === 'add') op.store.remove(op.eid);
  if (op.type === 'remove') op.store.addBack(op.entity);
}
function applyRedo(op) {
  if (op.type === 'update') op.store.update(op.eid, op.attr, op['new']);
  if (op.type === 'add') op.store.addBack(op.entity);
  if (op.type === 'remove') op.store.remove(op.eid);
}

function undo() {
  const entry = undoStack.pop();
  if (!entry) return;
  redoStack.push(entry);
  undoing = true;
  if (entry.type === 'batch') {
    for (let i = entry.ops.length - 1; i >= 0; i--) applyUndo(entry.ops[i]);
  } else {
    applyUndo(entry);
  }
  undoing = false;
}

function redo() {
  const entry = redoStack.pop();
  if (!entry) return;
  undoStack.push(entry);
  undoing = true;
  if (entry.type === 'batch') {
    for (const op of entry.ops) applyRedo(op);
  } else {
    applyRedo(entry);
  }
  undoing = false;
}

